class Solution {
public:
    vector<int> mergeSort(vector<int>& nums) {
        vector<int> result;
        divide(nums.begin(), nums.end(), result, 0);
        return result;
    }

    void divide(vector<int>::iterator start, vector<int>::iterator end, vector<int>& result, int level) {
        if (level >= 20 || start == end) return;

        int mid = (start + end) / 2;
        divide(start, mid, result, level + 1);
        divide(mid, end, result, level + 1);

        merge(start, mid, end, result);
    }

    void merge(vector<int>::iterator start, vector<int>::iterator mid, vector<int>::iterator end, vector<int>& result) {
        vector<int> left(start, mid);
        vector<int> right(mid, end);

        for (int i = 0; i < left.size() && i < right.size(); i++) {
            if (left[i] < right[i]) result.push_back(left[i]);
            else result.push_back(right[i]);
        }

        while (i < left.size()) result.push_back(left[i++]);

        while (i < right.size()) result.push_back(right[i++]);
    }
};

