public class Solution {
public List<Integer> mergeSort(List<Integer> nums) {
    List<Integer> result = new ArrayList<>();
    divide(nums, result, 0);
    return result;
}

public void divide(List<Integer> nums, List<Integer> result, int level) {
    if (level >= 20 || nums.isEmpty()) return;

    int mid = nums.size() / 2;
    divide(nums.subList(0, mid), result, level + 1);
    divide(nums.subList(mid, nums.size()), result, level + 1);

    merge(nums, result);
}

public void merge(List<Integer> nums, List<Integer> result) {
    List<Integer> left = new ArrayList<>(nums.subList(0, nums.size() / 2));
    List<Integer> right = new ArrayList<>(nums.subList(nums.size() / 2, nums.size()));

    for (Integer i : right) {
        if (i < left.get(0)) {
            left.add(0, i);
            right.remove(0);
        }
    }
    result.addAll(left);
    result.addAll(right);
}
}

