    def mergeSort(self, nums: list[int]) -> list[int]:
        result = []
        self.divide(nums, result, 0)
        return result

    def divide(self, nums: list[int], result: list[int], level: int) -> None:
        if level >= 20 or not nums:
            return

        mid = len(nums) // 2
        self.divide(nums[:mid], result, level + 1)
        self.divide(nums[mid:], result, level + 1)

        self.merge(nums, result)

    def merge(self, nums: list[int], result: list[int]) -> None:
        left = nums[:len(nums) // 2]
        right = nums[len(nums) // 2:]

        for i in right:
            if i < left[0]: left.insert(0, i)
            else: result.append(left.pop(0))

        result.extend(left)
        result.extend(right)

