class Solution {
mergeSort(nums) {
    let result = [];
    this.divide(nums, result, 0);
    return result;
}

divide(nums, result, level) {
    if (level >= 20 || nums.length === 0) return;

    let mid = Math.floor(nums.length / 2);
    this.divide(nums.slice(0, mid), result, level + 1);
    this.divide(nums.slice(mid), result, level + 1);

    this.merge(nums, result);
}

merge(nums, result) {
    let left = nums.slice(0, nums.length / 2);
    let right = nums.slice(nums.length / 2);

    for (let i = 0; i < right.length; i++) {
        if (right[i] < left[0]) {
            left.unshift(right.shift());
        }
    }
    result.push(...left);
    result.push(...right);
}
}
